{
  "name": "Magazino Inventory Pro",
  "description": "A high-fidelity inventory management system for tracking parts, shipments, and withdrawals with real-time stock calculation and validation.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'IN' | 'OUT';

export interface Part {
  pn: string;
  description: string;
  minStock?: number;
  location?: string;
  active: boolean;
}

export interface Person {
  personId: string;
  fullName: string;
  department?: string;
  active: boolean;
}

export interface Transaction {
  txId: string;
  timestamp: string;
  type: TransactionType;
  pn: string;
  qty: number;
  takenById?: string;
  receivedFrom?: string;
  note?: string;
  dttFile?: string;
}

export interface PartWithStock extends Part {
  stock: number;
}

export enum View {
  RECEIVE = 'Receive Shipment',
  PARTS = 'Parts',
  PEOPLE = 'People',
  WITHDRAW = 'Withdraw Item',
  HISTORY = 'History'
}

import { Part, Person } from './types';

export const INITIAL_PARTS: Part[] = [
  { pn: 'BRK-001', description: 'Front Brake Pad Set - High Performance', minStock: 10, location: 'Shelf A1', active: true },
  { pn: 'OIL-442', description: 'Synthetic Engine Oil 5W-30', minStock: 50, location: 'Shelf B2', active: true },
  { pn: 'FIL-990', description: 'Micro-Particulate Air Filter', minStock: 25, location: 'Shelf C4', active: true },
  { pn: 'SCR-102', description: 'M8 Stainless Steel Bolt', minStock: 200, location: 'Box 05', active: true },
  { pn: 'GSK-202', description: 'Valve Cover Gasket', minStock: 5, location: 'Shelf D1', active: true },
];

export const INITIAL_PEOPLE: Person[] = [
  { personId: 'EMP-1001', fullName: 'Mario Rossi', department: 'Assembly A', active: true },
  { personId: 'EMP-1002', fullName: 'Luigi Verdi', department: 'Assembly B', active: true },
  { personId: 'EMP-1003', fullName: 'Sofia Bianchi', department: 'Quality Control', active: true },
];

import React, { useState, useEffect, useMemo } from 'react';
import { View, Part, Person, Transaction, PartWithStock } from './types';
import { INITIAL_PARTS, INITIAL_PEOPLE } from './mockData';
import { PlusCircle, MinusCircle, Package, Users, History, Search, AlertTriangle, ChevronRight, X } from 'lucide-react';
import ReceiveForm from './components/ReceiveForm';
import WithdrawForm from './components/WithdrawForm';
import PartsView from './components/PartsView';
import PeopleView from './components/PeopleView';
import TransactionHistory from './components/TransactionHistory';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.PARTS);
  const [parts, setParts] = useState<Part[]>(() => {
    const saved = localStorage.getItem('magazino_parts');
    return saved ? JSON.parse(saved) : INITIAL_PARTS;
  });
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('magazino_people');
    return saved ? JSON.parse(saved) : INITIAL_PEOPLE;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('magazino_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('magazino_parts', JSON.stringify(parts));
  }, [parts]);

  useEffect(() => {
    localStorage.setItem('magazino_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('magazino_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Calculate Real-Time Stock
  const partsWithStock = useMemo(() => {
    return parts.map(part => {
      const partTx = transactions.filter(t => t.pn === part.pn);
      const stock = partTx.reduce((acc, t) => {
        return t.type === 'IN' ? acc + t.qty : acc - t.qty;
      }, 0);
      return { ...part, stock };
    });
  }, [parts, transactions]);

  const addTransaction = (tx: Transaction) => {
    setTransactions(prev => [tx, ...prev]);
  };

  const renderView = () => {
    switch (currentView) {
      case View.RECEIVE:
        return <ReceiveForm parts={parts} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.RECEIVE)} />;
      case View.WITHDRAW:
        return <WithdrawForm partsWithStock={partsWithStock} people={people} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.WITHDRAW)} />;
      case View.PARTS:
        return <PartsView parts={partsWithStock} transactions={transactions} />;
      case View.PEOPLE:
        return <PeopleView people={people} transactions={transactions} onAdd={(p) => setPeople([...people, p])} />;
      case View.HISTORY:
        return <TransactionHistory transactions={transactions} people={people} />;
      default:
        return <PartsView parts={partsWithStock} transactions={transactions} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-4xl mx-auto bg-white shadow-xl relative overflow-hidden">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-4 shadow-md sticky top-0 z-20 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-bold">Magazino Pro</h1>
          <p className="text-xs text-indigo-100 opacity-80">Inventory Management System</p>
        </div>
        <button 
          onClick={() => setCurrentView(View.HISTORY)}
          className={`p-2 rounded-full hover:bg-indigo-600 transition-colors ${currentView === View.HISTORY ? 'bg-indigo-800' : ''}`}
        >
          <History size={20} />
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 p-4 hide-scrollbar">
        {renderView()}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-4xl mx-auto bg-white border-t border-gray-200 z-30 flex justify-around items-center h-20 shadow-2xl">
        <NavButton 
          active={currentView === View.RECEIVE} 
          onClick={() => setCurrentView(View.RECEIVE)} 
          icon={<PlusCircle size={24} />} 
          label="Receive"
        />
        <NavButton 
          active={currentView === View.PARTS} 
          onClick={() => setCurrentView(View.PARTS)} 
          icon={<Package size={24} />} 
          label="Parts"
        />
        <NavButton 
          active={currentView === View.PEOPLE} 
          onClick={() => setCurrentView(View.PEOPLE)} 
          icon={<Users size={24} />} 
          label="People"
        />
        <NavButton 
          active={currentView === View.WITHDRAW} 
          onClick={() => setCurrentView(View.WITHDRAW)} 
          icon={<MinusCircle size={24} />} 
          label="Withdraw"
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center space-y-1 w-1/4 transition-colors duration-200 ${active ? 'text-indigo-600' : 'text-gray-400'}`}
  >
    <div className={`${active ? 'scale-110' : 'scale-100'} transition-transform duration-200`}>
      {icon}
    </div>
    <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { Part, Transaction, TransactionType } from '../types';
import { Save, RefreshCw } from 'lucide-react';

interface Props {
  parts: Part[];
  onSubmit: (tx: Transaction) => void;
  onRepeat: () => void;
}

const ReceiveForm: React.FC<Props> = ({ parts, onSubmit, onRepeat }) => {
  const [pn, setPn] = useState('');
  const [qty, setQty] = useState<number>(1);
  const [receivedFrom, setReceivedFrom] = useState('');
  const [note, setNote] = useState('');
  const [success, setSuccess] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pn || qty < 1) return;

    const newTx: Transaction = {
      txId: `TX-${Date.now()}`,
      timestamp: new Date().toISOString(),
      type: 'IN',
      pn,
      qty: Math.floor(qty),
      receivedFrom,
      note,
    };

    onSubmit(newTx);
    setSuccess(true);
    setTimeout(() => {
      setSuccess(false);
      setPn('');
      setQty(1);
      setReceivedFrom('');
      setNote('');
      onRepeat();
    }, 1500);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Receive Shipment</h2>
        <p className="text-sm text-gray-500">Record incoming stock to the magazine.</p>
      </div>

      {success ? (
        <div className="bg-green-100 border border-green-400 text-green-700 px-4 py-3 rounded relative flex items-center justify-center space-x-2 animate-bounce">
          <Save size={20} />
          <span className="font-bold">Entry Saved Successfully!</span>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Part Number (PN)</label>
            <select
              value={pn}
              onChange={(e) => setPn(e.target.value)}
              required
              className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none"
            >
              <option value="">Select a part...</option>
              {parts.filter(p => p.active).map(part => (
                <option key={part.pn} value={part.pn}>{part.pn} - {part.description}</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Quantity (Integer)</label>
              <input
                type="number"
                min="1"
                step="1"
                value={qty}
                onChange={(e) => setQty(parseInt(e.target.value))}
                required
                className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Received From</label>
              <input
                type="text"
                placeholder="Supplier / Agent"
                value={receivedFrom}
                onChange={(e) => setReceivedFrom(e.target.value)}
                required
                className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Note / Reference</label>
            <input
              type="text"
              placeholder="Shipment Ref / WO #"
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
            />
          </div>

          <div className="pt-4">
            <button
              type="submit"
              className="w-full flex items-center justify-center space-x-2 bg-indigo-600 text-white p-4 rounded-xl font-bold shadow-lg hover:bg-indigo-700 active:transform active:scale-95 transition-all"
            >
              <Save size={20} />
              <span>Submit Transaction</span>
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default ReceiveForm;

import React, { useState } from 'react';
import { PartWithStock, Person, Transaction } from '../types';
import { Save, AlertCircle } from 'lucide-react';

interface Props {
  partsWithStock: PartWithStock[];
  people: Person[];
  onSubmit: (tx: Transaction) => void;
  onRepeat: () => void;
}

const WithdrawForm: React.FC<Props> = ({ partsWithStock, people, onSubmit, onRepeat }) => {
  const [pn, setPn] = useState('');
  const [qty, setQty] = useState<number>(1);
  const [takenById, setTakenById] = useState('');
  const [note, setNote] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const selectedPart = partsWithStock.find(p => p.pn === pn);
  const availableStock = selectedPart?.stock || 0;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!pn || !takenById || qty < 1) {
      setError('Please fill all mandatory fields.');
      return;
    }

    if (qty > availableStock) {
      setError(`Insufficient stock! Only ${availableStock} units available.`);
      return;
    }

    const newTx: Transaction = {
      txId: `TX-${Date.now()}`,
      timestamp: new Date().toISOString(),
      type: 'OUT',
      pn,
      qty: Math.floor(qty),
      takenById,
      note,
    };

    onSubmit(newTx);
    setSuccess(true);
    setTimeout(() => {
      setSuccess(false);
      setPn('');
      setQty(1);
      setTakenById('');
      setNote('');
      onRepeat();
    }, 1500);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Withdraw Item</h2>
        <p className="text-sm text-gray-500">Log stock leaving the magazine for assembly teams.</p>
      </div>

      {success ? (
        <div className="bg-blue-100 border border-blue-400 text-blue-700 px-4 py-3 rounded relative flex items-center justify-center space-x-2 animate-pulse">
          <Save size={20} />
          <span className="font-bold">Withdrawal Recorded!</span>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Part Number (PN)</label>
            <select
              value={pn}
              onChange={(e) => {
                setPn(e.target.value);
                setError('');
              }}
              required
              className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 transition-all outline-none"
            >
              <option value="">Select part...</option>
              {partsWithStock.filter(p => p.active).map(part => (
                <option key={part.pn} value={part.pn}>
                  {part.pn} ({part.stock} in stock)
                </option>
              ))}
            </select>
            {selectedPart && (
              <div className="mt-2 p-2 bg-gray-100 rounded text-xs flex justify-between">
                <span className="text-gray-600">{selectedPart.description}</span>
                <span className={`font-bold ${selectedPart.stock <= (selectedPart.minStock || 0) ? 'text-red-600' : 'text-green-600'}`}>
                  STOCK: {selectedPart.stock}
                </span>
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Quantity</label>
              <input
                type="number"
                min="1"
                step="1"
                value={qty}
                onChange={(e) => {
                  setQty(parseInt(e.target.value));
                  setError('');
                }}
                required
                className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Withdrawn By</label>
              <select
                value={takenById}
                onChange={(e) => setTakenById(e.target.value)}
                required
                className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none"
              >
                <option value="">Select person...</option>
                {people.filter(p => p.active).map(person => (
                  <option key={person.personId} value={person.personId}>{person.fullName}</option>
                ))}
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Work Order / Note</label>
            <input
              type="text"
              placeholder="Internal Ref / Notes"
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="w-full p-3 bg-white border border-gray-300 rounded-lg shadow-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none"
            />
          </div>

          {error && (
            <div className="p-3 bg-red-50 border border-red-200 text-red-600 text-sm rounded-lg flex items-center space-x-2">
              <AlertCircle size={18} />
              <span>{error}</span>
            </div>
          )}

          <div className="pt-4">
            <button
              type="submit"
              className="w-full flex items-center justify-center space-x-2 bg-red-600 text-white p-4 rounded-xl font-bold shadow-lg hover:bg-red-700 active:transform active:scale-95 transition-all"
            >
              <Save size={20} />
              <span>Withdraw Units</span>
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default WithdrawForm;

import React, { useState, useMemo } from 'react';
import { PartWithStock, Transaction } from '../types';
import { Search, AlertTriangle, MapPin, Info, ChevronRight } from 'lucide-react';

interface Props {
  parts: PartWithStock[];
  transactions: Transaction[];
}

const PartsView: React.FC<Props> = ({ parts, transactions }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showLowStockOnly, setShowLowStockOnly] = useState(false);
  const [selectedPart, setSelectedPart] = useState<PartWithStock | null>(null);

  const filteredParts = useMemo(() => {
    let result = parts.filter(p => 
      p.pn.toLowerCase().includes(searchTerm.toLowerCase()) || 
      p.description.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (showLowStockOnly) {
      result = result.filter(p => p.stock <= (p.minStock || 0));
    }

    return result.sort((a, b) => a.stock - b.stock);
  }, [parts, searchTerm, showLowStockOnly]);

  const partHistory = useMemo(() => {
    if (!selectedPart) return [];
    return transactions
      .filter(t => t.pn === selectedPart.pn)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [selectedPart, transactions]);

  return (
    <div className="space-y-4">
      <div className="flex flex-col space-y-3 sticky top-0 bg-gray-50 pt-2 pb-4 z-10">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input
            type="text"
            placeholder="Search by PN or Description..."
            className="w-full pl-10 pr-4 py-3 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex items-center space-x-2">
          <button
            onClick={() => setShowLowStockOnly(!showLowStockOnly)}
            className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
              showLowStockOnly ? 'bg-orange-500 text-white shadow-md' : 'bg-white border text-gray-600'
            }`}
          >
            <AlertTriangle size={14} />
            <span>Low Stock Alert</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-3">
        {filteredParts.length > 0 ? (
          filteredParts.map(part => (
            <div 
              key={part.pn} 
              onClick={() => setSelectedPart(part)}
              className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer relative group"
            >
              <div className="flex justify-between items-start">
                <div className="space-y-1">
                  <div className="flex items-center space-x-2">
                    <span className="text-sm font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded">{part.pn}</span>
                    {part.stock <= (part.minStock || 0) && (
                      <span className="flex items-center text-[10px] text-orange-600 font-bold bg-orange-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">
                        <AlertTriangle size={10} className="mr-1" /> Reorder
                      </span>
                    )}
                  </div>
                  <h3 className="font-semibold text-gray-800 line-clamp-1">{part.description}</h3>
                  <div className="flex items-center space-x-3 text-xs text-gray-500">
                    <span className="flex items-center"><MapPin size={12} className="mr-1" /> {part.location || 'N/A'}</span>
                    <span className="flex items-center"><AlertTriangle size={12} className="mr-1" /> Min: {part.minStock || 0}</span>
                  </div>
                </div>
                <div className="text-right">
                  <div className={`text-2xl font-black ${part.stock <= (part.minStock || 0) ? 'text-red-500' : 'text-green-600'}`}>
                    {part.stock}
                  </div>
                  <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Units</div>
                </div>
              </div>
              <ChevronRight className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-300 group-hover:text-indigo-400" size={20} />
            </div>
          ))
        ) : (
          <div className="text-center py-20 bg-gray-100 rounded-3xl border-2 border-dashed border-gray-300">
            <Package className="mx-auto text-gray-400 mb-2" size={48} />
            <p className="text-gray-500 font-medium">No parts matching your search</p>
          </div>
        )}
      </div>

      {/* Part Details Modal */}
      {selectedPart && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-lg rounded-t-3xl sm:rounded-3xl shadow-2xl max-h-[90vh] flex flex-col overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50">
              <div>
                <h2 className="text-xl font-bold text-gray-800">{selectedPart.pn}</h2>
                <p className="text-sm text-gray-500">{selectedPart.description}</p>
              </div>
              <button onClick={() => setSelectedPart(null)} className="p-2 hover:bg-white rounded-full transition-colors">
                <Search size={24} className="rotate-45" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-gray-50 p-4 rounded-2xl text-center">
                  <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mb-1">Current Stock</p>
                  <p className={`text-4xl font-black ${selectedPart.stock <= (selectedPart.minStock || 0) ? 'text-red-500' : 'text-green-600'}`}>
                    {selectedPart.stock}
                  </p>
                </div>
                <div className="bg-gray-50 p-4 rounded-2xl text-center">
                  <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mb-1">Location</p>
                  <p className="text-xl font-bold text-gray-700">{selectedPart.location || 'Unknown'}</p>
                </div>
              </div>

              <div>
                <h3 className="text-sm font-bold text-gray-700 mb-3 flex items-center">
                  <History size={16} className="mr-2" />
                  Recent Transactions
                </h3>
                <div className="space-y-3">
                  {partHistory.length > 0 ? (
                    partHistory.slice(0, 10).map(t => (
                      <div key={t.txId} className="flex justify-between items-center p-3 rounded-lg border text-sm">
                        <div>
                          <span className={`font-bold ${t.type === 'IN' ? 'text-green-600' : 'text-red-600'}`}>
                            {t.type} {t.qty}
                          </span>
                          <p className="text-[10px] text-gray-400 uppercase">{new Date(t.timestamp).toLocaleDateString()} · {t.note || 'No note'}</p>
                        </div>
                        <div className="text-right text-xs text-gray-500">
                          {t.type === 'IN' ? t.receivedFrom : `By ${t.takenById}`}
