export default PartsView;

export type TransactionType = 'IN' | 'OUT';

export interface Part {
  pn: string;
  description: string;
  minStock?: number;
  location?: string;
  active: boolean;
}

export interface Person {
  personId: string;
  fullName: string;
  department?: string;
  active: boolean;
}

export interface Transaction {
  txId: string;
  timestamp: string;
  type: TransactionType;
  pn: string;
  qty: number;
  takenById?: string;
  receivedFrom?: string;
  note?: string;
  dttFile?: string;
}

export interface PartWithStock extends Part {
  stock: number;
}

export interface AppNotification {
  id: string;
  timestamp: string;
  title: string;
  message: string;
  type: 'LOW_STOCK' | 'SYSTEM';
  pn?: string;
  read: boolean;
}

export enum View {
  RECEIVE = 'Receive Shipment',
  PARTS = 'Parts',
  PEOPLE = 'People',
  WITHDRAW = 'Withdraw Item',
  HISTORY = 'History',
  NOTIFICATIONS = 'Notifications'
}

import React, { useState, useEffect, useMemo } from 'react';
import { View, Part, Person, Transaction, PartWithStock, AppNotification } from './types';
import { INITIAL_PARTS, INITIAL_PEOPLE } from './mockData';
import { PlusCircle, MinusCircle, Package, Users, History, Bell, AlertTriangle, X } from 'lucide-react';
import ReceiveForm from './components/ReceiveForm';
import WithdrawForm from './components/WithdrawForm';
import PartsView from './components/PartsView';
import PeopleView from './components/PeopleView';
import TransactionHistory from './components/TransactionHistory';
import NotificationCenter from './components/NotificationCenter';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.PARTS);
  const [parts, setParts] = useState<Part[]>(() => {
    const saved = localStorage.getItem('magazino_parts');
    return saved ? JSON.parse(saved) : INITIAL_PARTS;
  });
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('magazino_people');
    return saved ? JSON.parse(saved) : INITIAL_PEOPLE;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('magazino_transactions');
    return saved ? JSON.parse(saved) : [];
  });
  const [notifications, setNotifications] = useState<AppNotification[]>(() => {
    const saved = localStorage.getItem('magazino_notifications');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('magazino_parts', JSON.stringify(parts));
  }, [parts]);

  useEffect(() => {
    localStorage.setItem('magazino_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('magazino_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('magazino_notifications', JSON.stringify(notifications));
  }, [notifications]);

  // Calculate Real-Time Stock
  const partsWithStock = useMemo(() => {
    return parts.map(part => {
      const partTx = transactions.filter(t => t.pn === part.pn);
      const stock = partTx.reduce((acc, t) => {
        return t.type === 'IN' ? acc + t.qty : acc - t.qty;
      }, 0);
      return { ...part, stock };
    });
  }, [parts, transactions]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  const checkLowStock = (pn: string, currentTransactions: Transaction[]) => {
    const part = parts.find(p => p.pn === pn);
    if (!part || part.minStock === undefined) return;

    const stock = currentTransactions
      .filter(t => t.pn === pn)
      .reduce((acc, t) => (t.type === 'IN' ? acc + t.qty : acc - t.qty), 0);

    if (stock <= part.minStock) {
      const newNotification: AppNotification = {
        id: `NOTIF-${Date.now()}`,
        timestamp: new Date().toISOString(),
        title: 'Low Stock Alert',
        message: `Part ${part.pn} (${part.description}) has reached low stock: ${stock} units (Min: ${part.minStock}).`,
        type: 'LOW_STOCK',
        pn: part.pn,
        read: false,
      };

      // Simulate email sending logic
      console.log(`[MOCK EMAIL] To: Keeper, Subject: Low Stock Alert - ${part.pn}`);

      setNotifications(prev => [newNotification, ...prev]);
    }
  };

  const addTransaction = (tx: Transaction) => {
    const newTransactions = [tx, ...transactions];
    setTransactions(newTransactions);
    checkLowStock(tx.pn, newTransactions);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  const clearNotifications = () => {
    setNotifications([]);
  };

  const renderView = () => {
    switch (currentView) {
      case View.RECEIVE:
        return <ReceiveForm parts={parts} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.RECEIVE)} />;
      case View.WITHDRAW:
        return <WithdrawForm partsWithStock={partsWithStock} people={people} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.WITHDRAW)} />;
      case View.PARTS:
        return <PartsView parts={partsWithStock} transactions={transactions} />;
      case View.PEOPLE:
        return <PeopleView people={people} transactions={transactions} onAdd={(p) => setPeople([...people, p])} />;
      case View.HISTORY:
        return <TransactionHistory transactions={transactions} people={people} />;
      case View.NOTIFICATIONS:
        return <NotificationCenter notifications={notifications} onMarkRead={markAllRead} onClear={clearNotifications} />;
      default:
        return <PartsView parts={partsWithStock} transactions={transactions} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-4xl mx-auto bg-white shadow-xl relative overflow-hidden">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-4 shadow-md sticky top-0 z-20 flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <button onClick={() => setCurrentView(View.PARTS)} className="flex items-center space-x-2">
            <div className="bg-white text-indigo-700 p-1.5 rounded-lg">
              <Package size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold leading-none">Magazino Pro</h1>
              <p className="text-[10px] text-indigo-100 opacity-80 uppercase tracking-widest mt-1">Inventory Control</p>
            </div>
          </button>
        </div>
        <div className="flex items-center space-x-1">
          <button 
            onClick={() => setCurrentView(View.NOTIFICATIONS)}
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors relative ${currentView === View.NOTIFICATIONS ? 'bg-indigo-800' : ''}`}
          >
            <Bell size={20} />
            {unreadCount > 0 && (
              <span className="absolute top-1 right-1 bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-indigo-700 animate-pulse">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </button>
          <button 
            onClick={() => setCurrentView(View.HISTORY)}
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors ${currentView === View.HISTORY ? 'bg-indigo-800' : ''}`}
          >
            <History size={20} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 p-4 hide-scrollbar">
        {renderView()}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-4xl mx-auto bg-white border-t border-gray-200 z-30 flex justify-around items-center h-20 shadow-2xl">
        <NavButton 
          active={currentView === View.RECEIVE} 
          onClick={() => setCurrentView(View.RECEIVE)} 
          icon={<PlusCircle size={24} />} 
          label="Receive"
        />
        <NavButton 
          active={currentView === View.PARTS} 
          onClick={() => setCurrentView(View.PARTS)} 
          icon={<Package size={24} />} 
          label="Parts"
        />
        <NavButton 
          active={currentView === View.PEOPLE} 
          onClick={() => setCurrentView(View.PEOPLE)} 
          icon={<Users size={24} />} 
          label="People"
        />
        <NavButton 
          active={currentView === View.WITHDRAW} 
          onClick={() => setCurrentView(View.WITHDRAW)} 
          icon={<MinusCircle size={24} />} 
          label="Withdraw"
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center space-y-1 w-1/4 transition-colors duration-200 ${active ? 'text-indigo-600' : 'text-gray-400'}`}
  >
    <div className={`${active ? 'scale-110' : 'scale-100'} transition-transform duration-200`}>
      {icon}
    </div>
    <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
  </button>
);

export default App;

import React from 'react';
