import React, { useState, useRef } from 'react';
import { Part, Transaction } from '../types';
import { Save, Camera, X, Image as ImageIcon } from 'lucide-react';

interface Props {
  parts: Part[];
  onSubmit: (tx: Transaction) => void;
  onRepeat: () => void;
}

const ReceiveForm: React.FC<Props> = ({ parts, onSubmit, onRepeat }) => {
  const [pn, setPn] = useState('');
  const [qty, setQty] = useState<number>(1);
  const [receivedFrom, setReceivedFrom] = useState('');
  const [note, setNote] = useState('');
  const [dttFile, setDttFile] = useState<string>('');
  const [success, setSuccess] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDttFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pn || qty < 1) return;

    const newTx: Transaction = {
      txId: `TX-${Date.now()}`,
      timestamp: new Date().toISOString(),
      type: 'IN',
      pn,
      qty: Math.floor(qty),
      receivedFrom,
      note,
      dttFile,
    };

    onSubmit(newTx);
    setSuccess(true);
    setTimeout(() => {
      setSuccess(false);
      setPn('');
      setQty(1);
      setReceivedFrom('');
      setNote('');
      setDttFile('');
      onRepeat();
    }, 1500);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Receive Shipment</h2>
