import React, { useState, useRef } from 'react';
import { Part, Transaction } from '../types';
import { Save, Camera, X, Maximize2, Trash2 } from 'lucide-react';

interface Props {
  parts: Part[];
  onSubmit: (tx: Transaction) => void;
  onRepeat: () => void;
}

const ReceiveForm: React.FC<Props> = ({ parts, onSubmit, onRepeat }) => {
  const [pn, setPn] = useState('');
  const [qty, setQty] = useState<number>(1);
  const [receivedFrom, setReceivedFrom] = useState('');
  const [note, setNote] = useState('');
  const [dttFile, setDttFile] = useState<string>('');
  const [showFullImage, setShowFullImage] = useState(false);
  const [success, setSuccess] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDttFile(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pn || qty < 1) return;

    const newTx: Transaction = {
      txId: `TX-${Date.now()}`,
      timestamp: new Date().toISOString(),
      type: 'IN',
      pn,
      qty: Math.floor(qty),
      receivedFrom,
      note,
      dttFile,
    };

    onSubmit(newTx);
    setSuccess(true);
    setTimeout(() => {
      setSuccess(false);
      setPn('');
      setQty(1);
      setReceivedFrom('');
      setNote('');
      setDttFile('');
      onRepeat();
    }, 1500);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">Receive Shipment</h2>
        <p className="text-sm text-gray-500">Record incoming stock and document delivery notes.</p>
      </div>

      {success ? (
        <div className="bg-green-100 border border-green-400 text-green-700 px-4 py-8 rounded-2xl relative flex flex-col items-center justify-center space-y-2 animate-bounce">
          <Save size={32} />
          <span className="font-bold text-lg">Entry Saved Successfully!</span>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1.5">Part Number (PN)</label>
            <select
              value={pn}
              onChange={(e) => setPn(e.target.value)}
              required
              className="w-full p-3.5 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none"
            >
              <option value="">Select a part...</option>
              {parts.filter(p => p.active).map(part => (
                <option key={part.pn} value={part.pn}>{part.pn} - {part.description}</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1.5">Quantity (Integer)</label>
              <input
                type="number"
                min="1"
                step="1"
                value={qty}
                onChange={(e) => setQty(parseInt(e.target.value) || 0)}
                required
                className="w-full p-3.5 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1.5">Received From</label>
              <input
                type="text"
                placeholder="Supplier / Agent Name"
                value={receivedFrom}
                onChange={(e) => setReceivedFrom(e.target.value)}
                required
                className="w-full p-3.5 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1.5">Note / Reference</label>
            <input
              type="text"
              placeholder="Shipment Ref / WO # / Document ID"
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="w-full p-3.5 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
            />
          </div>

          {/* Camera Upload for DDT */}
          <div className="bg-gray-50 p-4 rounded-2xl border border-dashed border-gray-300">
            <label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-3">DDT / Delivery Note Photo</label>

            <div className="flex flex-wrap items-center gap-4">
              {!dttFile ? (
                <button
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className="flex flex-col items-center justify-center space-y-2 bg-white border-2 border-indigo-100 w-32 h-32 rounded-2xl hover:bg-indigo-50 hover:border-indigo-300 transition-all group"
                >
                  <Camera size={32} className="text-indigo-400 group-hover:text-indigo-600 transition-colors" />
                  <span className="text-xs font-bold text-indigo-500">Capture DDT</span>
                </button>
              ) : (
                <div className="relative group">
                  <div 
                    onClick={() => setShowFullImage(true)}
                    className="cursor-pointer relative overflow-hidden rounded-2xl border-4 border-white shadow-lg h-32 w-32"
                  >
                    <img 
                      src={dttFile} 
                      alt="DDT Preview" 
                      className="h-full w-full object-cover transition-transform group-hover:scale-110" 
                    />
                    <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <Maximize2 className="text-white" size={24} />
                    </div>
                  </div>
                  <button
                    type="button"
                    onClick={() => setDttFile('')}
                    className="absolute -top-3 -right-3 bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-xl transition-colors border-2 border-white"
                    title="Remove Photo"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              )}

              <input
                type="file"
                ref={fileInputRef}
                className="hidden"
                accept="image/*"
                capture="environment"
                onChange={handleCapture}
              />

              <div className="flex-1 min-w-[150px]">
                <p className="text-sm font-medium text-gray-700">Document Upload</p>
                <p className="text-[10px] text-gray-400 uppercase tracking-tighter mt-0.5 leading-tight">
                  Capture a clear photo of the transport document for accountability.
                </p>
              </div>
            </div>
          </div>

          <div className="pt-2">
            <button
              type="submit"
              className="w-full flex items-center justify-center space-x-2 bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-indigo-700 active:transform active:scale-95 transition-all"
            >
              <Save size={20} />
              <span>Submit Transaction</span>
            </button>
          </div>
        </form>
      )}

      {/* Full Size Image Modal */}
      {showFullImage && dttFile && (
        <div className="fixed inset-0 bg-black/90 z-[100] flex flex-col p-4 animate-in fade-in duration-200">
          <div className="flex justify-end p-2">
            <button 
              onClick={() => setShowFullImage(false)}
              className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-colors"
            >
              <X size={28} />
            </button>
          </div>
          <div className="flex-1 flex items-center justify-center overflow-hidden">
            <img 
              src={dttFile} 
              alt="DDT Full View" 
              className="max-h-full max-w-full object-contain rounded-lg shadow-2xl" 
            />
          </div>
          <div className="text-center p-6">
            <button 
              onClick={() => setShowFullImage(false)}
              className="px-8 py-3 bg-white text-gray-900 rounded-full font-bold shadow-lg"
            >
              Close Preview
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ReceiveForm;

export type TransactionType = 'IN' | 'OUT';

export interface Part {
  pn: string;
  description: string;
  minStock?: number;
  location?: string;
  active: boolean;
}

export interface Person {
  personId: string;
  fullName: string;
  department?: string;
  active: boolean;
}

export interface Transaction {
  txId: string;
  timestamp: string;
  type: TransactionType;
  pn: string;
  qty: number;
  takenById?: string;
  receivedFrom?: string;
  note?: string;
  dttFile?: string;
}

export interface PartWithStock extends Part {
  stock: number;
}

export interface AppNotification {
  id: string;
  timestamp: string;
  title: string;
  message: string;
  type: 'LOW_STOCK' | 'SYSTEM';
  pn?: string;
  read: boolean;
}

export enum View {
  RECEIVE = 'Receive Shipment',
  PARTS = 'Parts',
  PEOPLE = 'People',
  WITHDRAW = 'Withdraw Item',
  HISTORY = 'History',
  NOTIFICATIONS = 'Notifications',
  DOCUMENTS = 'Documents Archive'
}

import React, { useState, useEffect, useMemo } from 'react';
import { View, Part, Person, Transaction, PartWithStock, AppNotification } from './types';
import { INITIAL_PARTS, INITIAL_PEOPLE } from './mockData';
import { PlusCircle, MinusCircle, Package, Users, History, Bell, AlertTriangle, X, FileImage } from 'lucide-react';
import ReceiveForm from './components/ReceiveForm';
import WithdrawForm from './components/WithdrawForm';
import PartsView from './components/PartsView';
import PeopleView from './components/PeopleView';
import TransactionHistory from './components/TransactionHistory';
import NotificationCenter from './components/NotificationCenter';
import DocumentArchive from './components/DocumentArchive';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.PARTS);
  const [parts, setParts] = useState<Part[]>(() => {
    const saved = localStorage.getItem('magazino_parts');
    return saved ? JSON.parse(saved) : INITIAL_PARTS;
  });
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('magazino_people');
    return saved ? JSON.parse(saved) : INITIAL_PEOPLE;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('magazino_transactions');
    return saved ? JSON.parse(saved) : [];
  });
  const [notifications, setNotifications] = useState<AppNotification[]>(() => {
    const saved = localStorage.getItem('magazino_notifications');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('magazino_parts', JSON.stringify(parts));
  }, [parts]);

  useEffect(() => {
    localStorage.setItem('magazino_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('magazino_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('magazino_notifications', JSON.stringify(notifications));
  }, [notifications]);

  // Calculate Real-Time Stock
  const partsWithStock = useMemo(() => {
    return parts.map(part => {
      const partTx = transactions.filter(t => t.pn === part.pn);
      const stock = partTx.reduce((acc, t) => {
        return t.type === 'IN' ? acc + t.qty : acc - t.qty;
      }, 0);
      return { ...part, stock };
    });
  }, [parts, transactions]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  const checkLowStock = (pn: string, currentTransactions: Transaction[]) => {
    const part = parts.find(p => p.pn === pn);
    if (!part || part.minStock === undefined) return;

    const stock = currentTransactions
      .filter(t => t.pn === pn)
      .reduce((acc, t) => (t.type === 'IN' ? acc + t.qty : acc - t.qty), 0);

    if (stock <= part.minStock) {
      const newNotification: AppNotification = {
        id: `NOTIF-${Date.now()}`,
        timestamp: new Date().toISOString(),
        title: 'Low Stock Alert',
        message: `Part ${part.pn} (${part.description}) has reached low stock: ${stock} units (Min: ${part.minStock}).`,
        type: 'LOW_STOCK',
        pn: part.pn,
        read: false,
      };

      // Simulate email sending logic
      console.log(`[MOCK EMAIL] To: Keeper, Subject: Low Stock Alert - ${part.pn}`);

      setNotifications(prev => [newNotification, ...prev]);
    }
  };

  const addTransaction = (tx: Transaction) => {
    const newTransactions = [tx, ...transactions];
    setTransactions(newTransactions);
    checkLowStock(tx.pn, newTransactions);
  };

  const addPart = (part: Part) => {
    setParts(prev => [...prev, part]);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  const clearNotifications = () => {
    setNotifications([]);
  };

  const renderView = () => {
    switch (currentView) {
      case View.RECEIVE:
        return <ReceiveForm parts={parts} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.RECEIVE)} />;
      case View.WITHDRAW:
        return <WithdrawForm partsWithStock={partsWithStock} people={people} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.WITHDRAW)} />;
      case View.PARTS:
        return <PartsView parts={partsWithStock} transactions={transactions} onAddPart={addPart} />;
      case View.PEOPLE:
        return <PeopleView people={people} transactions={transactions} onAdd={(p) => setPeople([...people, p])} />;
      case View.HISTORY:
        return <TransactionHistory transactions={transactions} people={people} />;
      case View.NOTIFICATIONS:
        return <NotificationCenter notifications={notifications} onMarkRead={markAllRead} onClear={clearNotifications} />;
      case View.DOCUMENTS:
        return <DocumentArchive transactions={transactions} />;
      default:
        return <PartsView parts={partsWithStock} transactions={transactions} onAddPart={addPart} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-4xl mx-auto bg-white shadow-xl relative overflow-hidden">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-4 shadow-md sticky top-0 z-20 flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <button onClick={() => setCurrentView(View.PARTS)} className="flex items-center space-x-2 text-left">
            <div className="bg-white text-indigo-700 p-1.5 rounded-lg">
              <Package size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold leading-none">Magazino Pro</h1>
              <p className="text-[10px] text-indigo-100 opacity-80 uppercase tracking-widest mt-1">Inventory Control</p>
            </div>
          </button>
        </div>
        <div className="flex items-center space-x-1">
          <button 
            onClick={() => setCurrentView(View.DOCUMENTS)}
            title="DDT Archive"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors relative ${currentView === View.DOCUMENTS ? 'bg-indigo-800' : ''}`}
          >
            <FileImage size={20} />
          </button>
          <button 
            onClick={() => setCurrentView(View.NOTIFICATIONS)}
            title="Notifications"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors relative ${currentView === View.NOTIFICATIONS ? 'bg-indigo-800' : ''}`}
          >
            <Bell size={20} />
            {unreadCount > 0 && (
              <span className="absolute top-1 right-1 bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-indigo-700 animate-pulse">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </button>
          <button 
            onClick={() => setCurrentView(View.HISTORY)}
            title="Transaction History"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors ${currentView === View.HISTORY ? 'bg-indigo-800' : ''}`}
          >
            <History size={20} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 p-4 hide-scrollbar">
        {renderView()}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-4xl mx-auto bg-white border-t border-gray-200 z-30 flex justify-around items-center h-20 shadow-2xl">
        <NavButton 
          active={currentView === View.RECEIVE} 
          onClick={() => setCurrentView(View.RECEIVE)} 
          icon={<PlusCircle size={24} />} 
          label="Receive"
        />
        <NavButton 
          active={currentView === View.PARTS} 
          onClick={() => setCurrentView(View.PARTS)} 
          icon={<Package size={24} />} 
          label="Parts"
        />
        <NavButton 
          active={currentView === View.PEOPLE} 
          onClick={() => setCurrentView(View.PEOPLE)} 
          icon={<Users size={24} />} 
          label="People"
        />
        <NavButton 
          active={currentView === View.WITHDRAW} 
          onClick={() => setCurrentView(View.WITHDRAW)} 
          icon={<MinusCircle size={24} />} 
          label="Withdraw"
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center space-y-1 w-1/4 transition-colors duration-200 ${active ? 'text-indigo-600' : 'text-gray-400'}`}
  >
    <div className={`${active ? 'scale-110' : 'scale-100'} transition-transform duration-200`}>
      {icon}
    </div>
    <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
  </button>
);

export default App;

