export default TransactionHistory;

export type TransactionType = 'IN' | 'OUT';

export interface Part {
  pn: string;
  description: string;
  minStock?: number;
  location?: string;
  active: boolean;
}

export interface Person {
  personId: string;
  fullName: string;
  department?: string;
  active: boolean;
}

export interface Transaction {
  txId: string;
  timestamp: string;
  type: TransactionType;
  pn: string;
  qty: number;
  takenById?: string;
  receivedFrom?: string;
  note?: string;
  dttFile?: string;
}

export interface PartWithStock extends Part {
  stock: number;
}

export interface AppNotification {
  id: string;
  timestamp: string;
  title: string;
  message: string;
  type: 'LOW_STOCK' | 'SYSTEM';
  pn?: string;
  read: boolean;
}

export enum View {
  RECEIVE = 'Carico',
  PARTS = 'Inventario',
  PEOPLE = 'Personale',
  WITHDRAW = 'Scarico',
  HISTORY = 'Storico',
  NOTIFICATIONS = 'Notifiche',
  DOCUMENTS = 'Archivio DDT'
}

import React, { useState, useEffect, useMemo } from 'react';
import { View, Part, Person, Transaction, PartWithStock, AppNotification } from './types';
import { INITIAL_PARTS, INITIAL_PEOPLE } from './mockData';
import { PlusCircle, MinusCircle, Package, Users, History, Bell, AlertTriangle, X, FileImage } from 'lucide-react';
import ReceiveForm from './components/ReceiveForm';
import WithdrawForm from './components/WithdrawForm';
import PartsView from './components/PartsView';
import PeopleView from './components/PeopleView';
import TransactionHistory from './components/TransactionHistory';
import NotificationCenter from './components/NotificationCenter';
import DocumentArchive from './components/DocumentArchive';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.PARTS);
  const [parts, setParts] = useState<Part[]>(() => {
    const saved = localStorage.getItem('magazino_parts');
    return saved ? JSON.parse(saved) : INITIAL_PARTS;
  });
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('magazino_people');
    return saved ? JSON.parse(saved) : INITIAL_PEOPLE;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('magazino_transactions');
    return saved ? JSON.parse(saved) : [];
  });
  const [notifications, setNotifications] = useState<AppNotification[]>(() => {
    const saved = localStorage.getItem('magazino_notifications');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('magazino_parts', JSON.stringify(parts));
  }, [parts]);

  useEffect(() => {
    localStorage.setItem('magazino_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('magazino_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('magazino_notifications', JSON.stringify(notifications));
  }, [notifications]);

  // Calculate Real-Time Stock
  const partsWithStock = useMemo(() => {
    return parts.map(part => {
      const partTx = transactions.filter(t => t.pn === part.pn);
      const stock = partTx.reduce((acc, t) => {
        return t.type === 'IN' ? acc + t.qty : acc - t.qty;
      }, 0);
      return { ...part, stock };
    });
  }, [parts, transactions]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  const checkLowStock = (pn: string, currentTransactions: Transaction[]) => {
    const part = parts.find(p => p.pn === pn);
    if (!part || part.minStock === undefined) return;

    const stock = currentTransactions
      .filter(t => t.pn === pn)
      .reduce((acc, t) => (t.type === 'IN' ? acc + t.qty : acc - t.qty), 0);

    if (stock <= part.minStock) {
      const newNotification: AppNotification = {
        id: `NOTIF-${Date.now()}`,
        timestamp: new Date().toISOString(),
        title: 'Allerta Sottoscorta',
        message: `L'articolo ${part.pn} (${part.description}) è sottoscorta: ${stock} unità (Min: ${part.minStock}).`,
        type: 'LOW_STOCK',
        pn: part.pn,
        read: false,
      };

      console.log(`[MOCK EMAIL] A: Magazziniere, Oggetto: Allerta Sottoscorta - ${part.pn}`);
      setNotifications(prev => [newNotification, ...prev]);
    }
  };

  const addTransaction = (tx: Transaction) => {
    const newTransactions = [tx, ...transactions];
    setTransactions(newTransactions);
    checkLowStock(tx.pn, newTransactions);
  };

  const addPart = (part: Part) => {
    setParts(prev => [...prev, part]);
  };

  const deletePart = (pn: string) => {
    setParts(prev => prev.filter(p => p.pn !== pn));
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  const clearNotifications = () => {
    setNotifications([]);
  };

  const renderView = () => {
    switch (currentView) {
      case View.RECEIVE:
        return <ReceiveForm parts={parts} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.RECEIVE)} />;
      case View.WITHDRAW:
        return <WithdrawForm partsWithStock={partsWithStock} people={people} onSubmit={addTransaction} onRepeat={() => setCurrentView(View.WITHDRAW)} />;
      case View.PARTS:
        return <PartsView parts={partsWithStock} transactions={transactions} onAddPart={addPart} onDeletePart={deletePart} />;
      case View.PEOPLE:
        return <PeopleView people={people} transactions={transactions} onAdd={(p) => setPeople([...people, p])} />;
      case View.HISTORY:
        return <TransactionHistory transactions={transactions} people={people} />;
      case View.NOTIFICATIONS:
        return <NotificationCenter notifications={notifications} onMarkRead={markAllRead} onClear={clearNotifications} />;
      case View.DOCUMENTS:
        return <DocumentArchive transactions={transactions} />;
      default:
        return <PartsView parts={partsWithStock} transactions={transactions} onAddPart={addPart} onDeletePart={deletePart} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-4xl mx-auto bg-white shadow-xl relative overflow-hidden">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-4 shadow-md sticky top-0 z-20 flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <button onClick={() => setCurrentView(View.PARTS)} className="flex items-center space-x-2 text-left">
            <div className="bg-white text-indigo-700 p-1.5 rounded-lg">
              <Package size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold leading-none">Mondimpianti</h1>
              <p className="text-[10px] text-indigo-100 opacity-80 uppercase tracking-widest mt-1">Gestione Magazzino</p>
            </div>
          </button>
        </div>
        <div className="flex items-center space-x-1">
          <button 
            onClick={() => setCurrentView(View.DOCUMENTS)}
            title="Archivio DDT"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors relative ${currentView === View.DOCUMENTS ? 'bg-indigo-800' : ''}`}
          >
            <FileImage size={20} />
          </button>
          <button 
            onClick={() => setCurrentView(View.NOTIFICATIONS)}
            title="Notifiche"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors relative ${currentView === View.NOTIFICATIONS ? 'bg-indigo-800' : ''}`}
          >
            <Bell size={20} />
            {unreadCount > 0 && (
              <span className="absolute top-1 right-1 bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-indigo-700 animate-pulse">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </button>
          <button 
            onClick={() => setCurrentView(View.HISTORY)}
            title="Storico Movimenti"
            className={`p-2 rounded-full hover:bg-indigo-600 transition-colors ${currentView === View.HISTORY ? 'bg-indigo-800' : ''}`}
          >
            <History size={20} />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 p-4 hide-scrollbar">
        {renderView()}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-4xl mx-auto bg-white border-t border-gray-200 z-30 flex justify-around items-center h-20 shadow-2xl">
        <NavButton 
          active={currentView === View.RECEIVE} 
          onClick={() => setCurrentView(View.RECEIVE)} 
          icon={<PlusCircle size={24} />} 
          label="Carico"
        />
        <NavButton 
          active={currentView === View.PARTS} 
          onClick={() => setCurrentView(View.PARTS)} 
          icon={<Package size={24} />} 
          label="Inventario"
        />
        <NavButton 
          active={currentView === View.PEOPLE} 
          onClick={() => setCurrentView(View.PEOPLE)} 
          icon={<Users size={24} />} 
          label="Personale"
        />
        <NavButton 
          active={currentView === View.WITHDRAW} 
          onClick={() => setCurrentView(View.WITHDRAW)} 
          icon={<MinusCircle size={24} />} 
          label="Scarico"
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center space-y-1 w-1/4 transition-colors duration-200 ${active ? 'text-indigo-600' : 'text-gray-400'}`}
  >
    <div className={`${active ? 'scale-110' : 'scale-100'} transition-transform duration-200`}>
      {icon}
    </div>
    <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
  </button>
);

export default App;

import React, { useState, useMemo } from 'react';
import { Part, PartWithStock, Transaction } from '../types';
import { Search, AlertTriangle, MapPin, ChevronRight, Package, History, Plus, X, Save, Trash2 } from 'lucide-react';

interface Props {
  parts: PartWithStock[];
  transactions: Transaction[];
  onAddPart: (part: Part) => void;
  onDeletePart: (pn: string) => void;
}

const PartsView: React.FC<Props> = ({ parts, transactions, onAddPart, onDeletePart }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showLowStockOnly, setShowLowStockOnly] = useState(false);
  const [selectedPart, setSelectedPart] = useState<PartWithStock | null>(null);
  const [isAddingPart, setIsAddingPart] = useState(false);

  // New Part State
  const [newPn, setNewPn] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newMin, setNewMin] = useState<number>(0);
  const [newLoc, setNewLoc] = useState('');
  const [error, setError] = useState('');

  const filteredParts = useMemo(() => {
    let result = parts.filter(p => 
      p.pn.toLowerCase().includes(searchTerm.toLowerCase()) || 
      p.description.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (showLowStockOnly) {
      result = result.filter(p => p.stock <= (p.minStock || 0));
    }

    return result.sort((a, b) => a.stock - b.stock);
  }, [parts, searchTerm, showLowStockOnly]);

  const partHistory = useMemo(() => {
    if (!selectedPart) return [];
    return transactions
      .filter(t => t.pn === selectedPart.pn)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [selectedPart, transactions]);

  const handleAddPart = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const trimmedPn = newPn.trim().toUpperCase();
    if (!trimmedPn) {
      setError('Codice PN obbligatorio.');
      return;
    }

    if (parts.some(p => p.pn.toUpperCase() === trimmedPn)) {
      setError(`Il codice "${trimmedPn}" esiste già.`);
      return;
    }

    onAddPart({
      pn: trimmedPn,
      description: newDesc.trim() || 'Nessuna descrizione',
      minStock: newMin,
      location: newLoc.trim(),
      active: true,
    });

    setIsAddingPart(false);
    setNewPn('');
    setNewDesc('');
    setNewMin(0);
    setNewLoc('');
  };

  const handleDelete = () => {
    if (!selectedPart) return;
    if (window.confirm(`Sei sicuro di voler eliminare l'articolo ${selectedPart.pn}? Questa azione non può essere annullata.`)) {
      onDeletePart(selectedPart.pn);
      setSelectedPart(null);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col space-y-3 sticky top-0 bg-gray-50 pt-2 pb-4 z-10">
        <div className="flex items-center space-x-2">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              type="text"
              placeholder="Cerca PN o Descrizione..."
              className="w-full pl-10 pr-4 py-3 bg-white border border-gray-300 rounded-xl shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => setIsAddingPart(true)}
            className="bg-indigo-600 text-white p-3 rounded-xl shadow-lg hover:bg-indigo-700 active:scale-95 transition-all"
            title="Aggiungi Nuovo Articolo"
          >
            <Plus size={24} />
          </button>
        </div>
        <div className="flex items-center space-x-2">
          <button
            onClick={() => setShowLowStockOnly(!showLowStockOnly)}
            className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
              showLowStockOnly ? 'bg-orange-500 text-white shadow-md' : 'bg-white border text-gray-600'
            }`}
          >
            <AlertTriangle size={14} />
            <span>Sottoscorta</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-3">
        {filteredParts.length > 0 ? (
          filteredParts.map(part => (
            <div 
              key={part.pn} 
              onClick={() => setSelectedPart(part)}
              className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer relative group"
            >
              <div className="flex justify-between items-start">
                <div className="space-y-1">
                  <div className="flex items-center space-x-2">
                    <span className="text-sm font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded">{part.pn}</span>
                    {part.stock <= (part.minStock || 0) && (
                      <span className="flex items-center text-[10px] text-orange-600 font-bold bg-orange-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">
                        <AlertTriangle size={10} className="mr-1" /> Da Ordinare
                      </span>
                    )}
                  </div>
                  <h3 className="font-semibold text-gray-800 line-clamp-1">{part.description}</h3>
                  <div className="flex items-center space-x-3 text-xs text-gray-500">
                    <span className="flex items-center"><MapPin size={12} className="mr-1" /> {part.location || 'N/D'}</span>
                    <span className="flex items-center"><AlertTriangle size={12} className="mr-1" /> Min: {part.minStock || 0}</span>
                  </div>
                </div>
                <div className="text-right mr-6">
                  <div className={`text-2xl font-black ${part.stock <= (part.minStock || 0) ? 'text-red-500' : 'text-green-600'}`}>
                    {part.stock}
                  </div>
                  <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Unità</div>
                </div>
              </div>
              <ChevronRight className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-300 group-hover:text-indigo-400" size={20} />
            </div>
          ))
        ) : (
          <div className="text-center py-20 bg-gray-100 rounded-3xl border-2 border-dashed border-gray-300">
            <Package className="mx-auto text-gray-400 mb-2" size={48} />
            <p className="text-gray-500 font-medium">Nessun articolo trovato</p>
          </div>
        )}
      </div>

      {/* Add New Part Modal */}
      {isAddingPart && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
            <div className="p-6 bg-indigo-600 text-white flex justify-between items-center">
              <div>
                <h2 className="text-xl font-bold">Nuova Anagrafica Articolo</h2>
                <p className="text-xs opacity-80">Inserisci un nuovo codice nel sistema.</p>
              </div>
              <button onClick={() => setIsAddingPart(false)} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleAddPart} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-gray-500 mb-1">Codice Parte (PN) *</label>
                <input
                  type="text"
                  required
                  autoFocus
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={newPn}
                  onChange={(e) => setNewPn(e.target.value)}
                  placeholder="es. BRK-500"
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-gray-500 mb-1">Descrizione</label>
                <input
                  type="text"
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={newDesc}
                  onChange={(e) => setNewDesc(e.target.value)}
                  placeholder="Descrizione tecnica..."
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-gray-500 mb-1">Scorta Minima</label>
                  <input
                    type="number"
                    className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={newMin}
                    onChange={(e) => setNewMin(parseInt(e.target.value) || 0)}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-gray-500 mb-1">Posizione</label>
                  <input
                    type="text"
                    className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={newLoc}
                    onChange={(e) => setNewLoc(e.target.value)}
                    placeholder="Scaffale/Cesto..."
                  />
                </div>
              </div>

              {error && (
                <div className="p-3 bg-red-50 text-red-600 rounded-xl text-sm font-medium border border-red-100">
                  {error}
                </div>
              )}

              <button
                type="submit"
                className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center space-x-2"
              >
                <Save size={20} />
                <span>Salva Articolo</span>
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Part Details Modal */}
      {selectedPart && !isAddingPart && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-lg rounded-t-3xl sm:rounded-3xl shadow-2xl max-h-[90vh] flex flex-col overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className="p-6 border-b flex justify-between items-center bg-indigo-50">
              <div className="flex-1">
                <div className="flex items-center space-x-3">
                  <h2 className="text-xl font-bold text-gray-800">{selectedPart.pn}</h2>
                  <button 
                    onClick={handleDelete}
                    className="p-1.5 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    title="Elimina Articolo"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
                <p className="text-sm text-gray-500">{selectedPart.description}</p>
              </div>
