              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-20 text-gray-400">
            <History size={48} className="mx-auto mb-2 opacity-20" />
            <p>Nessun movimento registrato.</p>
          </div>
        )}
      </div>
    </div>
  );
};

